            </div>
            <div class="p-4 md:p-6 rounded-2xl bg-white dark:bg-white/5 border border-gray-200 dark:border-white/10 shadow-sm dark:shadow-none transition-colors duration-500">
              <h3 class="text-3xl md:text-4xl font-display font-bold text-[#b026ff] mb-1 md:mb-2">20+</h3>
