          </div>

          <!-- Decorative elements (optimized for performance) -->
          <div class="absolute -bottom-6 -left-6 w-32 h-32 bg-[#b026ff] rounded-full filter blur-[60px] opacity-20 dark:opacity-40 transition-opacity duration-500"></div>
