        </div>
      </div>
    </section>
  `
})
export class AboutComponent implements AfterViewInit {
  @ViewChild('aboutSection') section!: ElementRef;

  langService = inject(LanguageService);
  lang = this.langService.currentLang;

  private platformId = inject(PLATFORM_ID);

  ngAfterViewInit() {
    if (isPlatformBrowser(this.platformId)) {
      inView(this.section.nativeElement, () => {
        const content = this.section.nativeElement.querySelector('.about-content');
        const image = this.section.nativeElement.querySelector('.about-image');

        animate(content, { opacity: [0, 1], x: [-30, 0] }, { duration: 0.8, ease: [0.22, 1, 0.36, 1] });
        animate(image, { opacity: [0, 1], x: [30, 0] }, { duration: 0.8, ease: [0.22, 1, 0.36, 1], delay: 0.2 });
      }, { margin: "-100px" });
    }
  }
}

