import { Component, ChangeDetectionStrategy, PLATFORM_ID, inject, OnInit, computed } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { animate, inView, stagger } from 'motion';
import { LanguageService } from '../services/language.service';

interface Article {
  id: string;
  title: string;
  date: string;
  snippet: string;
  readTime: string;
}

@Component({
  selector: 'app-articles',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <section class="py-12 lg:py-24" id="articles">
      <div class="mb-12 lg:mb-16 sticky top-16 lg:top-28 z-30 bg-gray-50/90 dark:bg-[#050505]/90 backdrop-blur-xl py-4 rounded-2xl">
        <h2 class="text-3xl sm:text-4xl lg:text-5xl font-display font-bold text-gray-900 dark:text-white mb-4 sm:mb-6 tracking-tight">{{ lang() === 'id' ? 'Catatan & Artikel' : 'Notes & Articles' }}</h2>
        <div class="h-1 sm:h-1.5 w-16 sm:w-24 bg-gradient-to-r from-[#b026ff] to-[#00f0ff] rounded-full"></div>
      </div>

      <div class="grid grid-cols-2 gap-3 sm:gap-6">
        @for (article of articles(); track article.id) {
          <article class="article-card group relative p-4 sm:p-8 rounded-2xl sm:rounded-3xl bg-white dark:bg-[#111] border border-gray-100 dark:border-white/5 shadow-sm hover:shadow-xl transition-all duration-500 overflow-hidden cursor-pointer flex flex-col">
            <!-- Hover Gradient Background -->
            <div class="absolute inset-0 bg-gradient-to-br from-[#b026ff]/5 to-[#00f0ff]/5 opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none"></div>

            <div class="relative z-10 flex-1 flex flex-col">
              <div class="flex flex-wrap items-center gap-2 sm:gap-4 text-[9px] sm:text-sm text-gray-500 dark:text-gray-400 mb-2 sm:mb-4">
                <time [attr.datetime]="article.date">{{ article.date }}</time>
                <span class="w-1 h-1 rounded-full bg-gray-300 dark:bg-gray-600"></span>
                <span>{{ article.readTime }}</span>
              </div>

              <h3 class="text-xs sm:text-2xl font-bold text-gray-900 dark:text-white mb-2 sm:mb-3 group-hover:text-[#b026ff] dark:group-hover:text-[#00f0ff] transition-colors duration-300 line-clamp-2">
                {{ article.title }}
              </h3>

              <p class="text-[10px] sm:text-base text-gray-600 dark:text-gray-400 leading-relaxed mb-4 sm:mb-6 line-clamp-3 sm:line-clamp-none mt-auto">
                {{ article.snippet }}
              </p>

              <div class="flex items-center text-[9px] sm:text-sm font-bold text-gray-900 dark:text-white uppercase tracking-widest group-hover:text-[#b026ff] dark:group-hover:text-[#00f0ff] transition-colors duration-300 mt-auto pt-2">
                <span class="hidden sm:inline">{{ lang() === 'id' ? 'Baca Selengkapnya' : 'Read More' }}</span>
                <span class="sm:hidden">{{ lang() === 'id' ? 'Baca' : 'Read' }}</span>
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="ml-1 sm:ml-2 transform group-hover:translate-x-1 transition-transform duration-300 scale-75 sm:scale-100"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
              </div>
            </div>
          </article>
        }
      </div>
    </section>
  `,
  styles: []
})
export class ArticlesComponent implements OnInit {
  private platformId = inject(PLATFORM_ID);

  langService = inject(LanguageService);
  lang = this.langService.currentLang;

  articles = computed<Article[]>(() => {
    const isId = this.lang() === 'id';
    return [
      {
        id: '1',
        title: isId ? 'Cara Saya Mengoptimalkan Query SQL Server di Dasbor OEE' : 'How I Optimized SQL Server Queries in the OEE Dashboard',
        date: isId ? '15 Mar 2026' : 'Mar 15, 2026',
        readTime: isId ? '5 mnt baca' : '5 min read',
        snippet: isId ? 'Menghadapi jutaan baris data sensor per hari membutuhkan strategi indexing dan partisi tabel yang tepat. Berikut adalah studi kasus bagaimana saya mengurangi waktu muat dasbor dari 12 detik menjadi di bawah 1 detik.' : 'Handling millions of rows of sensor data per day requires proper indexing and table partitioning strategies. Here is a case study on how I reduced dashboard load time from 12 seconds to under 1 second.'
      },
      {
        id: '2',
        title: isId ? 'Menghubungkan Mesin IoT dengan React: Pola WebSocket yang Tangguh' : 'Connecting IoT Machines with React: Resilient WebSocket Patterns',
        date: isId ? '28 Feb 2026' : 'Feb 28, 2026',
        readTime: isId ? '7 mnt baca' : '7 min read',
        snippet: isId ? 'Membangun koneksi real-time antara perangkat keras industri dan antarmuka web modern memiliki tantangannya sendiri, terutama dalam menangani koneksi yang terputus dan sinkronisasi status.' : 'Building real-time connections between industrial hardware and modern web interfaces has its own challenges, especially in handling dropped connections and state synchronization.'
      },
      {
        id: '3',
        title: isId ? 'Arsitektur Clean Code untuk Aplikasi Skala Pabrik' : 'Clean Code Architecture for Factory-Scale Applications',
        date: isId ? '10 Jan 2026' : 'Jan 10, 2026',
        readTime: isId ? '6 mnt baca' : '6 min read',
        snippet: isId ? 'Mengapa memisahkan domain logic dari infrastruktur sangat penting ketika membangun perangkat lunak yang akan digunakan oleh ratusan operator di lantai pabrik setiap harinya.' : 'Why separating domain logic from infrastructure is crucial when building software that will be used by hundreds of operators on the factory floor every day.'
      }
    ];
  });

  ngOnInit() {
    if (isPlatformBrowser(this.platformId)) {
      setTimeout(() => this.initAnimations(), 100);
    }
  }

  initAnimations() {
    inView('#articles', () => {
      animate(
        '.article-card',
        { opacity: [0, 1], y: [40, 0] },
        { 
          delay: stagger(0.15),
          duration: 0.8, 
          ease: [0.22, 1, 0.36, 1] 
        }
      );
    });
  }
}

