import { Component, ChangeDetectionStrategy, HostListener, ElementRef, ViewChild } from '@angular/core';
import { animate } from 'motion';

@Component({
  selector: 'app-custom-cursor',
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div #cursor class="fixed top-0 left-0 w-8 h-8 rounded-full border-2 border-[#00f0ff] pointer-events-none z-[100] mix-blend-difference hidden md:block transition-colors duration-500" style="transform: translate(-50%, -50%)"></div>
    <div #dot class="fixed top-0 left-0 w-2 h-2 bg-[#b026ff] rounded-full pointer-events-none z-[100] hidden md:block transition-colors duration-500" style="transform: translate(-50%, -50%)"></div>
  `
})
export class CustomCursorComponent {
  @ViewChild('cursor') cursor!: ElementRef<HTMLDivElement>;
  @ViewChild('dot') dot!: ElementRef<HTMLDivElement>;

  mouseX = 0;
  mouseY = 0;

  @HostListener('window:mousemove', ['$event'])
  onMouseMove(event: MouseEvent) {
    this.mouseX = event.clientX;
    this.mouseY = event.clientY;

    if (this.dot?.nativeElement) {
      this.dot.nativeElement.style.transform = `translate(calc(${this.mouseX}px - 50%), calc(${this.mouseY}px - 50%))`;
    }

    if (this.cursor?.nativeElement) {
      animate(this.cursor.nativeElement, {
        x: this.mouseX,
        y: this.mouseY
      }, { duration: 0.15, ease: "easeOut" });
    }
  }
}

