import { Component, ChangeDetectionStrategy, ElementRef, ViewChild, AfterViewInit, PLATFORM_ID, inject, computed } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { MatIconModule } from '@angular/material/icon';
import { animate, inView, stagger } from 'motion';
import { LanguageService } from '../services/language.service';

@Component({
  selector: 'app-skills',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [MatIconModule],
  template: `
    <section class="" #skillsSection>
      <div class="text-center mb-8 md:mb-12 skill-header sticky top-16 lg:top-28 z-30 bg-gray-50/90 dark:bg-[#050505]/90 backdrop-blur-xl py-4 rounded-2xl">
        <h2 class="text-2xl md:text-4xl font-display font-bold mb-3 md:mb-4 tracking-tight">{{ lang() === 'id' ? 'Gudang Teknis' : 'Technical Arsenal' }}</h2>
        <p class="text-gray-600 dark:text-gray-400 max-w-2xl mx-auto text-sm md:text-base font-light transition-colors duration-500">{{ lang() === 'id' ? 'Alat dan teknologi yang saya gunakan untuk membangun perangkat lunak dan sistem industri yang tangguh.' : 'Tools and technologies I use to build robust software and industrial systems.' }}</p>
      </div>

      <div class="grid grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">
        @for (category of skillCategories(); track category.id) {
          <div class="skill-card opacity-0 p-3 sm:p-5 md:p-6 rounded-2xl bg-white dark:bg-white/5 border border-gray-200 dark:border-white/10 hover:bg-gray-50 dark:hover:bg-white/10 hover:-translate-y-2 hover:shadow-[0_10px_30px_-10px_rgba(176,38,255,0.15)] transition-all duration-300 group shadow-sm dark:shadow-none">
            <div class="w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 rounded-xl bg-gradient-to-br from-[#b026ff]/10 to-[#00f0ff]/10 dark:from-[#b026ff]/20 dark:to-[#00f0ff]/20 flex items-center justify-center mb-3 sm:mb-4 md:mb-6 group-hover:scale-110 group-hover:rotate-3 transition-all duration-300">
              <mat-icon class="text-[#00f0ff] scale-50 sm:scale-75 md:scale-90 group-hover:text-gray-900 dark:group-hover:text-white transition-colors">{{ category.icon }}</mat-icon>
            </div>
            <h3 class="text-sm sm:text-base md:text-xl font-bold mb-2 sm:mb-3 md:mb-4 tracking-tight group-hover:text-[#00f0ff] transition-colors">{{ category.title }}</h3>
            <ul class="space-y-1.5 sm:space-y-2 md:space-y-3">
              @for (skill of category.skills; track skill) {
                <li class="flex items-start sm:items-center gap-1.5 sm:gap-2 md:gap-3 text-gray-500 dark:text-gray-400 font-light text-[11px] sm:text-xs lg:text-sm group-hover:text-gray-700 dark:group-hover:text-gray-300 transition-colors">
                  <div class="w-1 h-1 rounded-full bg-[#b026ff] group-hover:scale-150 group-hover:bg-[#00f0ff] transition-all mt-1 sm:mt-0 shrink-0"></div>
                  <span class="leading-tight">{{ skill }}</span>
                </li>
              }
            </ul>
          </div>
        }
      </div>
    </section>
  `
})
export class SkillsComponent implements AfterViewInit {
  @ViewChild('skillsSection') section!: ElementRef;

  langService = inject(LanguageService);
  lang = this.langService.currentLang;

  private platformId = inject(PLATFORM_ID);

  skillCategories = computed(() => [
    {
      id: 'frontend',
      title: this.lang() === 'id' ? 'Antarmuka' : 'Frontend',
      icon: 'web',
      skills: ['React', 'TailwindCSS', 'HTML/CSS', 'JavaScript/TypeScript']
    },
    {
      id: 'backend',
      title: this.lang() === 'id' ? 'Sistem Belakang' : 'Backend',
      icon: 'dns',
      skills: ['ASP.NET Core', 'Laravel', 'Express.js', 'REST APIs']
    },
    {
      id: 'database',
      title: this.lang() === 'id' ? 'Basis Data' : 'Database',
      icon: 'storage',
      skills: ['SQL Server', 'MySQL', 'SQLite', this.lang() === 'id' ? 'Desain Basis Data' : 'Database Design']
    },
    {
      id: 'industrial',
      title: this.lang() === 'id' ? 'Industri' : 'Industrial',
      icon: 'precision_manufacturing',
      skills: ['SCADA', 'Sistem OEE', 'MES', 'Integrasi IoT', 'AVEVA Edge']
    }
  ]);

  ngAfterViewInit() {
    if (isPlatformBrowser(this.platformId)) {
      inView(this.section.nativeElement, () => {
        const header = this.section.nativeElement.querySelector('.skill-header');
        const cards = this.section.nativeElement.querySelectorAll('.skill-card');

        animate(header, { opacity: [0, 1], y: [20, 0] }, { duration: 0.6, ease: [0.22, 1, 0.36, 1] });
        animate(cards, { opacity: [0, 1], y: [30, 0] }, { delay: stagger(0.1, { startDelay: 0.2 }), duration: 0.8, ease: [0.22, 1, 0.36, 1] });
      }, { margin: "-100px" });
    }
  }
}
